import{_ as p,o as a,c as t,ag as r}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"第4集：天亮之前","description":"","frontmatter":{"title":"第4集：天亮之前","outline":false},"headers":[],"relativePath":"novels/jin-gu-yao/drama/04.md","filePath":"novels/jin-gu-yao/drama/04.md","lastUpdated":1774160915000}'),m={name:"novels/jin-gu-yao/drama/04.md"};function o(n,e,s,l,h,i){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="第-4-集-天亮之前" tabindex="-1">第 4 集：天亮之前 <a class="header-anchor" href="#第-4-集-天亮之前" aria-label="Permalink to &quot;第 4 集：天亮之前&quot;">​</a></h1><blockquote><p>钩子类型：紧张感 + 倒计时 时长：约 3 分钟</p></blockquote><hr><h2 id="【开场】" tabindex="-1">【开场】 <a class="header-anchor" href="#【开场】" aria-label="Permalink to &quot;【开场】&quot;">​</a></h2><p><em>字幕：五月十八日，寅时。天还黑。</em></p><p><em>三娘穿好男装，照铜镜。镜子里的人像个清瘦少年——但腰上鼓了一块。</em></p><p><em>她低头看了看——是令武的小布老虎。她随手塞进去的，怕路上他闹。</em></p><p><em>她把镜子翻过去，扣在桌上。</em></p><hr><h2 id="【院子里的混乱】" tabindex="-1">【院子里的混乱】 <a class="header-anchor" href="#【院子里的混乱】" aria-label="Permalink to &quot;【院子里的混乱】&quot;">​</a></h2><p><em>马三宝正在跟两个孩子搏斗。</em></p><p><em>柴哲威倒是乖，背着小包袱站着，一脸严肃，像个出征的小将军。</em></p><p><em>柴令武被从被窝里薅出来，半梦半醒且暴怒，骑在马三宝脖子上拽他头发。</em></p><p><strong>柴令武</strong>：要骑马——</p><p><strong>马三宝</strong>：这不是马这是我——哎哟！</p><p><em>三娘走过来，把令武抱下来。小家伙搂住她脖子，脸埋进肩窝。</em></p><p><strong>柴令武</strong>（迷糊）：爹爹呢……</p><p><em>三娘拍拍他的背。令武睡着了。</em></p><p><strong>三娘</strong>：走吧。</p><hr><h2 id="【出城】" tabindex="-1">【出城】 <a class="header-anchor" href="#【出城】" aria-label="Permalink to &quot;【出城】&quot;">​</a></h2><p><em>角门鱼贯而出。七个仆从，两匹马，三个大人，两个小孩。天边没有一丝光。</em></p><p><em>柴哲威走在三娘旁边，仰头看她的男装。</em></p><p><strong>柴哲威</strong>（压低声音）：娘，你穿成这样，不像男人。</p><p><strong>三娘</strong>：哪里不像？</p><p><strong>柴哲威</strong>（认真想了想）：男人不会走路这么好看。</p><p><em>马三宝在后面差点被口水呛到。</em></p><p><em>三娘没理他们，加快脚步。</em></p><hr><h2 id="【路上-·-紧张升级】" tabindex="-1">【路上 · 紧张升级】 <a class="header-anchor" href="#【路上-·-紧张升级】" aria-label="Permalink to &quot;【路上 · 紧张升级】&quot;">​</a></h2><p><em>一行人出了坊门，向南走。天际线有一条极淡的光。</em></p><p><em>忽然——远处传来马蹄声。</em></p><p><em>所有人僵住。</em></p><p><em>马三宝下意识挡到三娘和孩子前面。</em></p><p><em>马蹄声越来越近。</em></p><p><em>三娘把令武抱紧了一些，另一只手按住了腰间——</em></p><p><em>（特写：她的手摸到的不是刀，是那只小布老虎。）</em></p><p><em>几匹马从巷子口闪过。是巡夜的金吾卫，没有往这边看。</em></p><p><em>马蹄声远去。所有人松了一口气。</em></p><p><em>马三宝后背全是汗。</em></p><p><strong>马三宝</strong>（低声）：夫——公子，这也太——</p><p><strong>三娘</strong>（低声）：走。别停。</p><hr><h2 id="【出城门】" tabindex="-1">【出城门】 <a class="header-anchor" href="#【出城门】" aria-label="Permalink to &quot;【出城门】&quot;">​</a></h2><p><em>天快亮了。他们混在出城的商队里，过了南门。</em></p><p><em>柴哲威回头看了一眼长安。</em></p><p><strong>柴哲威</strong>（小声）：娘，我们还回来吗？</p><p><em>三娘没有回答。她也回头看了一眼。</em></p><p><em>长安的城墙在晨光里慢慢变亮。她在这座城里出生、长大、嫁人、生子。</em></p><p><em>她转过头。</em></p><p><strong>三娘</strong>：走。</p><p><em>怀里的柴令武翻了个身，把口水流到了她肩膀上。</em></p><hr><h2 id="【第-4-集钩子】" tabindex="-1">【第 4 集钩子】 <a class="header-anchor" href="#【第-4-集钩子】" aria-label="Permalink to &quot;【第 4 集钩子】&quot;">​</a></h2><p><em>画面切到鄠县——</em></p><p><em>县衙。天刚亮。</em></p><p><em>那个中年人站在院子里，对一个手下说话。</em></p><p><strong>中年人</strong>：去李氏庄园附近，找个地方住下。不要惊动任何人。有人来，有人走，你都给我记下来。</p><p><strong>手下</strong>：大人，您觉得李家的人会来？</p><p><em>中年人看着南边的天际线。</em></p><p><strong>中年人</strong>：不是觉得。是一定会来。</p><p><em>他笑了一下。</em></p><p><strong>中年人</strong>：问题是——来的是谁。</p><p><em>字幕：</em></p><p><strong>&quot;三娘以为自己在布局。但有人的棋，下得更早。&quot;</strong></p><hr><p><em>第 4 集 完</em></p>',67)])])}const c=p(m,[["render",o]]);export{g as __pageData,c as default};
